-        if name == column {
-            return Ok(true);
+    if !rows.is_empty() {
+        for row in &rows {
+            let name: String = row.get_named("name").unwrap_or_default();
+            if name == column {
+                return Ok(true);
+            }
         }
+        return Ok(false);
+    }
+    // Fallback: try to SELECT the column directly.
+    let probe = format!("SELECT \"{column}\" FROM \"{table}\" LIMIT 0");
+    match conn.query_sync(&probe, &[]) {
+        Ok(_) => Ok(true),
+        Err(_) => Ok(false),
     }
-    Ok(false)
 }

